// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		sendError(ctx, "Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		sendError(ctx, "URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		sendError(ctx, "Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		sendError(ctx, "URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Resolve host to check for private IP addresses
	host := parsedURL.Hostname()
	ipAddr := net.ParseIP(host)
	if ipAddr != nil {
		if isPrivateIP(ipAddr) {
			sendError(ctx, "Access to private IP addresses is blocked", fasthttp.StatusForbidden)
			return
		}
	} else {
		// If hostname is provided, resolve it to an IP to check
		ips, err := net.LookupIP(host)
		if err != nil {
			sendError(ctx, "Failed to resolve hostname", fasthttp.StatusBadGateway)
			return
		}
		for _, ip := range ips {
			if isPrivateIP(ip) {
				sendError(ctx, "Access to private IP addresses is blocked", fasthttp.StatusForbidden)
				return
			}
		}
	}

	// Create a custom dialer with timeout
	dialer := &fasthttp.TCPDialer{
		Concurrency:      4096,
		DNSCacheDuration: time.Hour,
	}

	// Use fasthttp.Client to fetch with timeout
	client := &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			return dialer.DialTimeout(addr, 5*time.Second)
		},
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 60 * time.Second,
		MaxConnsPerHost:     10,
		MaxResponseBodySize: 2 * 1024 * 1024, // Limit response body size
