// isLocalhost checks if the hostname is localhost
func isLocalhost(host string) bool {
	return host == "localhost" || 
		   host == "127.0.0.1" || 
		   host == "::1" ||
		   strings.HasPrefix(strings.ToLower(host), "localhost.")
}

// isPrivateIP checks if the IP address is private
func isPrivateIP(host string) bool {
	ip := net.ParseIP(host)
	if ip == nil {
		// If host is not an IP, we resolve it to check if it resolves to a private IP
		ips, err := net.LookupIP(host)
		if err != nil {
			return false
		}
		for _, i := range ips {
			if isPrivateIP(i.String()) {
				return true
			}
		}
		return false
	}

	// Check for private IP ranges
	return ip.IsLoopback() ||
		ip.IsPrivate() ||
		ip.IsUnspecified() ||
		ip.IsLinkLocalUnicast() ||
		ip.IsLinkLocalMulticast()
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	z := html.NewTokenizer(r)
	var foundTitle bool

	for {
		tt := z.Next()
		switch tt {
		case html.ErrorToken:
			return title, description, nil
		case html.StartTagToken, html.EndTagToken:
			t := z.Token()
			tagName := strings.ToLower(t.Data)

			if tagName == "title" && t.Type == html.StartTagToken {
				tt = z.Next()
				if tt == html.TextToken {
					title = strings.TrimSpace(html.UnescapeString(string(z.Text())))
					foundTitle = true
				}
			} else if tagName == "head" && t.Type == html.EndTagToken && foundTitle {
				// We've passed the title in head, can stop looking for title
				continue
			} else if tagName == "meta" {
				var name, property, content string
				for _, attr := range t.Attr {
					if attr.Key == "name" {
						name = strings.ToLower(attr.Val)
					} else if attr.Key == "property" {
						property = strings.ToLower(attr.Val)
					} else if attr.Key == "content" {
						content = attr.Val
					}
				}

				if (name == "description" || property == "og:description") && content != "" {
					description = strings.TrimSpace(html.UnescapeString(content))
				}
			}
		}
	}
}

