	"golang.org/x/net/html"
)

type RequestBody struct {
	URL string `json:"url"`
}

type ResponseBody struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

func isLocalAddress(host string) bool {
	ip := net.ParseIP(host)
	if ip == nil {
		// Try to resolve hostname
		addrs, err := net.LookupIP(host)
		if err != nil {
			return false
		}
		for _, addr := range addrs {
			if isLocalAddress(addr.String()) {
				return true
			}
		}
		return false
	}

	return ip.IsLoopback() || 
		   ip.IsPrivate() || 
		   ip.IsUnspecified() || 
		   ip.Equal(net.IPv4(169, 254, 0, 0).To4()) || // Link-local
		   ip.Equal(net.IPv4(127, 0, 0, 1).To4()) || // Loopback
		   (ip.To4() != nil && ip.Equal(net.ParseIP("::1"))) // IPv6 loopback
}

func validateURL(rawURL string) error {
	u := fasthttp.AcquireURI()
	defer fasthttp.ReleaseURI(u)

	if err := u.Parse(nil, []byte(rawURL)); err != nil {
		return fmt.Errorf("invalid URL format: %v", err)
	}

	host := string(u.Host())

	// Check if host is an IP address
	if ip := net.ParseIP(host); ip != nil {
		if isLocalAddress(host) {
			return fmt.Errorf("local IP addresses are not allowed")
		}
	} else {
		// Resolve hostname to IPs and check each one
		ips, err := net.LookupIP(host)
		if err != nil {
			// If DNS resolution fails, we still want to continue
			// but let's try to see if it looks like a local address pattern
		} else {
			for _, ip := range ips {
				if isLocalAddress(ip.String()) {
					return fmt.Errorf("hostname resolves to a local IP address: %s", ip.String())
				}
			}
		}
	}

	return nil
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	var reqBody RequestBody
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(ResponseBody{
			Error: "Invalid JSON",
		})
		return
	}

	if reqBody.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(ResponseBody{
			Error: "URL is required",
		})
		return
	}

