		})
		return
	}

	client := &fasthttp.Client{}
	client.Dial = fasthttp.DialDualStack

	// Set timeout for request
	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod("GET")

	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	// Use DoDeadline instead of DoRedirects to set timeout
	reqTimeout := time.Second * 10
	err := client.DoDeadline(req, resp, time.Now().Add(reqTimeout))
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(ResponseBody{
			Error: fmt.Sprintf("Failed to fetch URL: %v", err),
		})
		return
	}

	if resp.StatusCode() != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(ResponseBody{
			Error: fmt.Sprintf("Non-success status code: %d", resp.StatusCode()),
		})
		return
	}

	contentType := string(resp.Header.ContentType())
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(ResponseBody{
			Error: "URL does not return HTML content",
		})
		return
	}

	htmlContent := resp.Body()

	title, description := parseHTML(htmlContent)

	response := ResponseBody{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json")
	json.NewEncoder(ctx).Encode(response)
}

func parseHTML(body []byte) (string, string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var title, description string
	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && title == "" {
				title = extractText(n.FirstChild)
			}
			if n.Data == "meta" {
				var name, property, content string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						name = attr.Val
					case "property":
						property = attr.Val
					case "content":
						content = attr.Val
					}
				}
				if name == "description" || property == "og:description" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return strings.TrimSpace(title), strings.TrimSpace(description)
}

func extractText(n *html.Node) string {
	if n == nil {
		return ""
	}
	if n.Type == html.TextNode {
		return n.Data
	}
	var text string
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		text += extractText(c)
	}
	return text
}

func main() {
	fmt.Println("Starting server on :8080")
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		fmt.Printf("Error starting server: %v\n", err)
	}
}

