// isLocalIP checks if the IP address belongs to private/local networks
func isLocalIP(ipStr string) bool {
	ip := net.ParseIP(ipStr)
	if ip == nil {
		return false
	}

	// Check for loopback addresses
	if ip.IsLoopback() {
		return true
	}

	// Check for private network ranges
	privateNetworks := []*net.IPNet{
		{IP: net.ParseIP("10.0.0.0"), Mask: net.CIDRMask(8, 32)},
		{IP: net.ParseIP("172.16.0.0"), Mask: net.CIDRMask(12, 32)},
		{IP: net.ParseIP("192.168.0.0"), Mask: net.CIDRMask(16, 32)},
		{IP: net.ParseIP("127.0.0.0"), Mask: net.CIDRMask(8, 32)},
		{IP: net.ParseIP("169.254.0.0"), Mask: net.CIDRMask(16, 32)}, // Link-local
		{IP: net.IPv6loopback, Mask: net.CIDRMask(128, 128)},        // IPv6 loopback
	}

	for _, network := range privateNetworks {
		if network.Contains(ip) {
			return true
		}
	}

	return false
}

// resolveAndValidateHost resolves the hostname and validates that it's not a local address
func resolveAndValidateHost(host string) error {
	// Split host and port if present
	hostPort := host
	if idx := strings.LastIndex(host, ":"); idx != -1 {
		hostPort = host[:idx]
	}

	ips, err := net.LookupIP(hostPort)
	if err != nil {
		// If DNS lookup fails, try direct resolution
		ip := net.ParseIP(hostPort)
		if ip != nil {
			ips = []net.IP{ip}
		} else {
			return fmt.Errorf("could not resolve host: %s", hostPort)
		}
	}

	for _, ip := range ips {
		if isLocalIP(ip.String()) {
			return fmt.Errorf("host resolves to a local IP address: %s", ip.String())
		}
	}

	return nil
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if string(ctx.Method()) == "POST" {
		var req struct {
			URL string `json:"url"`
		}

		body := ctx.PostBody()
		if err := json.Unmarshal(body, &req); err != nil {
			ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
			return
		}

		targetURL := strings.TrimSpace(req.URL)
		if targetURL == "" {
			ctx.Error("URL is required", fasthttp.StatusBadRequest)
			return
		}

		// Parse and validate URL
		parsedURL, err := url.ParseRequestURI(targetURL)
		if err != nil {
			ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
			return
		}

		if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
			ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
			return
		}

		// Validate host to prevent SSRF attacks
		if err := resolveAndValidateHost(parsedURL.Host); err != nil {
			ctx.Error("Invalid host: "+err.Error(), fasthttp.StatusBadRequest)
			return
		}

		// Use fasthttp.Client to fetch with timeout and custom dialer to prevent SSRF
		client := &fasthttp.Client{
			ReadTimeout:         30 * time.Second,
			WriteTimeout:        30 * time.Second,
			MaxIdleConnDuration: 30 * time.Second,
			MaxConnsPerHost:     10,
			Dial: func(addr string) (net.Conn, error) {
				dialer := &net.Dialer{
					Timeout:   30 * time.Second,
					KeepAlive: 30 * time.Second,
				}

				conn, err := dialer.DialContext(context.Background(), "tcp", addr)
				if err != nil {
					return nil, err
				}

				// Get remote IP and validate it
				remoteAddr := conn.RemoteAddr().(*net.TCPAddr)
				if isLocalIP(remoteAddr.IP.String()) {
					conn.Close()
					return nil, fmt.Errorf("connection to local address blocked: %s", remoteAddr.IP.String())
				}

				return conn, nil
			},
		}

		freq := fasthttp.AcquireRequest()
		res := fasthttp.AcquireResponse()
		defer fasthttp.ReleaseRequest(freq)
		defer fasthttp.ReleaseResponse(res)

		freq.SetRequestURI(targetURL)
		freq.Header.SetMethod("GET")
		freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

		maxRedirectCounts := 5
		if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
			ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
			return
