// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)
	var foundTitle bool
	var inHead bool

	for {
		tokenType := tokenizer.Next()
		if tokenType == html.ErrorToken {
			// End of document reached
			break
		}

		token := tokenizer.Token()

		switch tokenType {
		case html.StartTagToken:
			tagName := token.Data
			if tagName == "head" {
				inHead = true
			} else if tagName == "title" && inHead {
				tokenType = tokenizer.Next()
				if tokenType == html.TextToken {
					title = strings.TrimSpace(tokenizer.Token().Data)
					foundTitle = true
				}
			} else if tagName == "meta" {
				var name, property, content string
				for _, attr := range token.Attr {
					if attr.Key == "name" {
						name = attr.Val
					} else if attr.Key == "property" {
						property = attr.Val
					} else if attr.Key == "content" {
						content = attr.Val
					}
				}
				// Check for description in either 'name' or 'property' attributes
				if (name == "description" || property == "og:description") && content != "" {
					description = strings.TrimSpace(content)
				}
			}

		case html.EndTagToken:
			if token.Data == "head" {
				inHead = false
				// If we've processed the entire head and didn't find a title,
				// continue to check other possible tokens
			}

		case html.SelfClosingTagToken:
			if token.Data == "meta" {
				var name, property, content string
				for _, attr := range token.Attr {
					if attr.Key == "name" {
						name = attr.Val
					} else if attr.Key == "property" {
						property = attr.Val
					} else if attr.Key == "content" {
						content = attr.Val
					}
				}
				// Check for description in either 'name' or 'property' attributes
				if (name == "description" || property == "og:description") && content != "" {
					description = strings.TrimSpace(content)
				}
			}
		}

		// Optimization: stop parsing once both title and description are found
		if foundTitle && description != "" {
			break
		}
	}

	return title, description, nil
}

