	"strings"
	"time"

	"github.com/valyala/fasthttp"
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Parse and validate URL
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Prevent SSRF by checking for internal IP addresses
	host := parsedURL.Hostname()
	if isLocalhost(host) || isPrivateIP(host) {
		ctx.Error("Access to local or private IPs is not allowed", fasthttp.StatusForbidden)
		return
	}

	// Resolve hostname to IP to check for internal IPs
	ips, err := net.LookupIP(host)
	if err == nil {
		for _, ip := range ips {
			if ip.IsLoopback() || ip.IsPrivate() || ip.IsUnspecified() {
				ctx.Error("Access to local or private IPs is not allowed", fasthttp.StatusForbidden)
				return
			}
		}
	}

	// Use fasthttp.Client to fetch with timeout
	client := &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			return fasthttp.DialDualStackTimeout(addr, 10*time.Second)
		},
		ReadTimeout:         30 * time.Second,
		WriteTimeout:        30 * time.Second,
		MaxIdleConnDuration: 30 * time.Second,
		MaxConnsPerHost:     2,
		MaxResponseBodySize: 5 * 1024 * 1024, // Limit response size to 5MB
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	maxRedirectCounts := 5 // Limit redirects to prevent loops
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// isLocalhost checks if the host is localhost
func isLocalhost(host string) bool {
	lowerHost := strings.ToLower(host)
	return lowerHost == "localhost" || lowerHost == "127.0.0.1" || lowerHost == "::1"
}

// isPrivateIP checks if the IP address is private
func isPrivateIP(host string) bool {
	ip := net.ParseIP(host)
	if ip == nil {
		return false
	}

	return ip.IsLoopback() || ip.IsPrivate() || ip.IsUnspecified()
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	// This is a simplified implementation that looks for basic title and meta tags
	data, err := io.ReadAll(r)
	if err != nil {
		return "", "", err
	}

	htmlStr := string(data)

	// Extract title
	titleStart := strings.Index(htmlStr, "<title>")
	if titleStart != -1 {
		titleEnd := strings.Index(htmlStr[titleStart:], "</title>")
		if titleEnd != -1 {
			title = strings.TrimSpace(htmlStr[titleStart+7 : titleStart+titleEnd])
		}
	}

	// Extract meta description
	descIndex := strings.Index(strings.ToLower(htmlStr), "<meta")
	if descIndex != -1 {
		descEnd := strings.Index(htmlStr[descIndex:], ">")
		if descEnd != -1 {
			metaTag := htmlStr[descIndex : descIndex+descEnd+1]
			if strings.Contains(strings.ToLower(metaTag), "name=\"description\"") || 
			   strings.Contains(strings.ToLower(metaTag), "name='description'") ||
			   strings.Contains(strings.ToLower(metaTag), "property=\"og:description\"") ||
			   strings.Contains(strings.ToLower(metaTag), "property='og:description'") {

				contentStart := strings.Index(strings.ToLower(metaTag), "content=\"")
				if contentStart == -1 {
					contentStart = strings.Index(strings.ToLower(metaTag), "content='")
				}
				if contentStart != -1 {
					contentPart := metaTag[contentStart+9:]
					quote := string(contentPart[0])
					contentPart = contentPart[1:]
					contentEnd := strings.Index(contentPart, quote)
					if contentEnd != -1 {
						description = strings.TrimSpace(contentPart[:contentEnd])
					}
				}
			}
		}
	}

	return title, description, nil
}

