)

type RequestBody struct {
	URL string `json:"url"`
}

type ResponseBody struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	var reqBody RequestBody
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(ResponseBody{Error: "Invalid JSON"})
		return
	}

	if reqBody.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(ResponseBody{Error: "URL is required"})
		return
	}

	client := &fasthttp.Client{
		Dial:            fasthttp.DialDualStack,
		ReadTimeout:     3 * time.Second,
		WriteTimeout:    3 * time.Second,
		MaxIdleConnDuration: 3 * time.Second,
	}

	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()

	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(reqBody.URL)

	if err := client.DoRedirects(req, resp, 5); err != nil { // Follow up to 5 redirects
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(ResponseBody{Error: fmt.Sprintf("Failed to fetch URL: %v", err)})
		return
	}

	if resp.StatusCode() != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(ResponseBody{Error: fmt.Sprintf("Received non-200 status code: %d", resp.StatusCode())})
		return
	}

	bodyBytes := resp.Body()
	title, description := parseHTML(bodyBytes)

	response := ResponseBody{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json")
	json.NewEncoder(ctx).Encode(response)
}

func parseHTML(data []byte) (string, string) {
	doc, err := html.Parse(strings.NewReader(string(data)))
	if err != nil {
		return "", ""
	}

	var title, description string
	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil {
					title = n.FirstChild.Data
				}
			case "meta":
				var name, property, content string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						name = attr.Val
					case "property":
						property = attr.Val
					case "content":
						content = attr.Val
					}
				}
				if name == "description" || property == "og:description" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return strings.TrimSpace(title), strings.TrimSpace(description)
}

