	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(url)

	err := client.DoRedirects(req, resp, 10) // Follow up to 10 redirects
	if err != nil {
		return "", "", fmt.Errorf("failed to fetch URL: %w", err)
	}

	if resp.StatusCode() != fasthttp.StatusOK {
		return "", "", fmt.Errorf("received non-OK status code: %d", resp.StatusCode())
	}

	body := resp.Body()

	// Handle Brotli compression if needed
	if string(resp.Header.Peek("Content-Encoding")) == "br" {
		brReader := brotli.NewReader(bytes.NewReader(body))
		decompressed, err := io.ReadAll(brReader)
		if err != nil {
