package main

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
	"net"
	"net/url"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
	"golang.org/x/net/html/atom"
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Parse the URL to check host
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Block private IP addresses
	host := parsedURL.Host
	if isPrivateIP(host) {
		ctx.Error("Access to private IPs is forbidden", fasthttp.StatusForbidden)
		return
	}

	// Use fasthttp.Client to fetch with timeout
	client := &fasthttp.Client{
		Dial:                fasthttp.DialDualStack,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 60 * time.Second,
		MaxConnsPerHost:     2,
		MaxResponseBodySize: 1024 * 1024, // Limit response size to 1MB
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	maxRedirectCounts := 5
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// isPrivateIP checks if the host resolves to a private IP address
func isPrivateIP(host string) bool {
	// Remove port if present
	host = strings.Split(host, ":")[0]

	// Check if it's an IP address directly
	ip := net.ParseIP(host)
	if ip != nil {
		return ip.IsPrivate() || ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast()
	}

	// Resolve hostname to IP
	ips, err := net.LookupIP(host)
	if err != nil {
		// If DNS resolution fails, we can't determine - safest to assume private
		return true
	}

	for _, ip := range ips {
		if ip.IsPrivate() || ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
			return true
		}
	}

	return false
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)
	var foundTitle bool
	var foundDescription bool

	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			return title, description, nil // End of document
		case html.StartTagToken, html.SelfClosingTagToken:
			tok := tokenizer.Token()

			// Look for meta tags with name="description" or property="og:description"
			if tok.DataAtom == atom.Meta {
				var nameAttr, propertyAttr, contentAttr string

				for _, attr := range tok.Attr {
					if strings.EqualFold(attr.Key, "name") {
						nameAttr = attr.Val
					} else if strings.EqualFold(attr.Key, "property") {
						propertyAttr = attr.Val
					} else if strings.EqualFold(attr.Key, "content") {
						contentAttr = attr.Val
					}
				}

				if (strings.EqualFold(nameAttr, "description") || 
					strings.EqualFold(propertyAttr, "og:description")) && 
					contentAttr != "" && description == "" {
					description = contentAttr
					foundDescription = true
				}
			}

			// If both title and description are found, we can stop parsing
			if foundTitle && foundDescription {
				return title, description, nil
			}

		case html.EndTagToken:
			tok := tokenizer.Token()
			if tok.DataAtom == atom.Title && title == "" {
				// Read next token which should be text
				nextTok := tokenizer.Next()
				if nextTok == html.TextToken {
					title = strings.TrimSpace(html.UnescapeString(tokenizer.Token().Data))
					foundTitle = true

					// If both title and description are found, we can stop parsing
					if foundTitle && foundDescription {
						return title, description, nil
					}
				}
			}
		}
	}
}

