// isPrivateIP checks if the hostname resolves to a private IP address
func isPrivateIP(host string) bool {
	ips, err := net.LookupIP(host)
	if err != nil {
		// If we can't resolve, assume it's safe to continue with validation
		return false
	}
	for _, ip := range ips {
		if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
			return true
		}
	}
	return false
}

// isLocalhost checks if host is localhost or similar
func isLocalhost(host string) bool {
	lowerHost := strings.ToLower(host)
	return lowerHost == "localhost" ||
		lowerHost == "localhost." ||
		strings.HasPrefix(lowerHost, "localhost:") ||
		strings.HasSuffix(lowerHost, ".localhost") ||
		strings.Contains(lowerHost, "localhost.")
}

// sanitizeString removes potentially harmful characters
func sanitizeString(s string) string {
	// Remove control characters and trim whitespace
	s = strings.Map(func(r rune) rune {
		if r >= 0x7F || r <= 0x1F {
			return -1
		}
		return r
	}, s)
	return strings.TrimSpace(s)
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	z := html.NewTokenizer(r)

	for {
		tt := z.Next()
		switch tt {
		case html.ErrorToken:
			return title, description, nil // End of document
		case html.StartTagToken, html.EndTagToken:
			token := z.Token()
			tagName := token.Data

			// Look for title tag
			if tagName == "title" && tt == html.StartTagToken {
				if next := z.Next(); next == html.TextToken {
					title = html.UnescapeString(string(z.Text()))
				}
			}

			// Look for meta tags
			if tagName == "meta" && tt == html.StartTagToken {
				var nameAttr, propertyAttr, contentAttr string
				for _, attr := range token.Attr {
					if attr.Key == "name" {
						nameAttr = attr.Val
					} else if attr.Key == "property" {
						propertyAttr = attr.Val
					} else if attr.Key == "content" {
						contentAttr = attr.Val
					}
				}

				// Check for description in name or property attributes
				if nameAttr == "description" || propertyAttr == "og:description" {
					description = html.UnescapeString(contentAttr)
				}
			}
		}
	}
}

