	"encoding/json"
	"fmt"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

type RequestBody struct {
	URL string `json:"url"`
}

type ResponseBody struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	var reqBody RequestBody
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(ResponseBody{Error: "Invalid JSON"})
		return
	}

	if reqBody.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(ResponseBody{Error: "URL is required"})
		return
	}

	client := &fasthttp.Client{
		Dial:               fasthttp.DialDualStack,
		ReadTimeout:        3 * time.Second,
		WriteTimeout:       3 * time.Second,
		MaxResponseBodySize: 1024 * 1024, // 1MB limit
	}

	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	req.SetRequestURI(reqBody.URL)

	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	// Use DoRedirects with timeout
	err := client.DoRedirects(req, resp, 10) // follow up to 10 redirects
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(ResponseBody{Error: err.Error()})
		return
	}

	if resp.StatusCode() != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(ResponseBody{Error: fmt.Sprintf("HTTP %d", resp.StatusCode())})
		return
	}

	contentType := string(resp.Header.ContentType())
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		ctx.SetStatusCode(fasthttp.StatusUnsupportedMediaType)
		json.NewEncoder(ctx).Encode(ResponseBody{Error: "Content is not HTML"})
		return
	}

	body := resp.Body()

	title, description := parseHTML(body)

	response := ResponseBody{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json")
	json.NewEncoder(ctx).Encode(response)
}

func parseHTML(htmlContent []byte) (title, description string) {
	z := html.NewTokenizer(strings.NewReader(string(htmlContent)))

	inTitle := false
	inHead := false
	for {
		tt := z.Next()
		switch tt {
		case html.ErrorToken:
			return // End of document
		case html.StartTagToken, html.EndTagToken:
			tn, _ := z.TagName()
			tagStr := string(tn)

			if tagStr == "head" {
				if tt == html.StartTagToken {
					inHead = true
				} else {
					inHead = false
				}
			} else if inHead && tagStr == "title" && tt == html.StartTagToken {
				inTitle = true
			} else if inHead && tagStr == "meta" && tt == html.StartTagToken {
				key, keyOk := getAttribute(z, "name")
				value, valueOk := getAttribute(z, "content")

				if keyOk && strings.ToLower(key) == "description" && valueOk {
					description = value
				}

				// Also check for og:description
				property, propOk := getAttribute(z, "property")
				if propOk && strings.ToLower(property) == "og:description" && valueOk {
					description = value
				}
			}

		case html.TextToken:
			if inTitle {
				title = string(z.Text())
				inTitle = false
			}
		}
	}
}

func getAttribute(z *html.Tokenizer, attrName string) (string, bool) {
	for {
		key, val, more := z.TagAttr()
		if string(key) == attrName {
			return string(val), true
		}
		if !more {
			break
		}
	}
	return "", false
}

func main() {
	// Example usage of the handler
	fmt.Println("Server starting...")
	fasthttp.ListenAndServe(":8080", FetchURLPreview)
}

