					}
				}

				if isPrivateIP(ipAddr.IP) {
					return nil, fmt.Errorf("connection to private IP address is not allowed")
				}
			}

			return (&net.Dialer{
				Timeout:   30 * time.Second,
				KeepAlive: 30 * time.Second,
			}).DialContext(context.Background(), "tcp", addr)
		},
