func isPrivateIP(host string) bool {
	// This is a simplified check - in production you might want to resolve the hostname and check the IP
	// For now, we'll just check common private ranges in string form
	privateCIDRs := []string{
		"10.", "172.16.", "172.17.", "172.18.", "172.19.",
