// sanitizeString removes potentially dangerous characters
func sanitizeString(s string) string {
	s = strings.ReplaceAll(s, "\n", "")
	s = strings.ReplaceAll(s, "\r", "")
	s = strings.TrimSpace(s)
	return s
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var traverse func(*html.Node)
	foundTitle := false
	foundDescription := false

	traverse = func(n *html.Node) {
		if foundTitle && foundDescription {
			return // Stop when both are found
		}

		if n.Type == html.ElementNode {
			if n.Data == "title" && !foundTitle {
				if n.FirstChild != nil {
					title = n.FirstChild.Data
					foundTitle = true
				}
			} else if n.Data == "meta" && !foundDescription {
				var name, property, content string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						name = attr.Val
					case "property":
						property = attr.Val
					case "content":
						content = attr.Val
					}
				}
				if (name == "description" || property == "og:description") && content != "" {
					description = content
					foundDescription = true
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			if !foundTitle || !foundDescription {
				traverse(c)
			} else {
				break
			}
		}
	}

	traverse(doc)
	return title, description, nil
}

