func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	var reqBody RequestBody
	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(ResponseBody{
			Error: "Invalid JSON",
		})
		return
	}

	if reqBody.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(ResponseBody{
			Error: "URL is required",
		})
		return
	}

	client := &fasthttp.Client{
		Dial:               fasthttp.DialDualStack,
		ReadTimeout:        3 * time.Second,
		WriteTimeout:       3 * time.Second,
		MaxIdleConnDuration: 3 * time.Second,
	}

	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	req.SetRequestURI(reqBody.URL)

	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	err := client.DoRedirects(req, resp, 5) // max 5 redirects
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(ResponseBody{
			Error: err.Error(),
		})
		return
	}

	contentType := string(resp.Header.ContentType())
	if !isHTMLContentType(contentType) {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(ResponseBody{
			Error: "URL does not return HTML content",
		})
		return
	}

	body := resp.Body()

	title, description := parseHTMLContent(body)

	response := ResponseBody{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json")
	json.NewEncoder(ctx).Encode(response)
}

func isHTMLContentType(contentType string) bool {
	return contains(contentType, "text/html") || contains(contentType, "application/xhtml+xml")
}

func contains(s, substr string) bool {
	for i := 0; i <= len(s)-len(substr); i++ {
		if s[i:i+len(substr)] == substr {
			return true
		}
	}
	return false
}

func parseHTMLContent(body []byte) (title, description string) {
	z := html.NewTokenizer(bytes.NewReader(body))

	inTitleTag := false
	inHeadTag := false

	for {
		tt := z.Next()
		switch tt {
		case html.ErrorToken:
			return // End of document or error
		case html.StartTagToken, html.EndTagToken:
			tn, _ := z.TagName()
			tag := string(tn)

			if tag == "head" {
				if tt == html.StartTagToken {
					inHeadTag = true
				} else {
					inHeadTag = false
				}
			}

			if !inHeadTag {
				continue
			}

			if tag == "title" && tt == html.StartTagToken {
				inTitleTag = true
			} else if tag == "meta" && tt == html.StartTagToken {
				key, keyOk := getAttribute(z, "name")
				value, valueOk := getAttribute(z, "content")

				if keyOk && valueOk && key == "description" {
					description = value
				}

				// Also check for og:description
				if keyOk && valueOk && key == "og:description" {
					description = value
				}
			}

		case html.TextToken:
			text := string(z.Text())
			if inTitleTag {
				title = text
				inTitleTag = false
			}
		}
	}
}

func getAttribute(z *html.Tokenizer, attrName string) (value string, found bool) {
	for {
		key, val, more := z.TagAttr()
		if string(key) == attrName {
			return string(val), true
		}
		if !more {
			break
		}
	}
	return "", false
}

