// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Prevent SSRF by resolving hostname and checking for internal addresses
	host := parsedURL.Hostname()
	ipList, err := net.LookupIP(host)
	if err != nil {
		// If DNS resolution fails, still check the hostname directly
		if isInternalAddress(host) {
			ctx.Error("SSRF protection: Invalid host", fasthttp.StatusBadRequest)
			return
		}
	} else {
		// Check each resolved IP
		for _, ip := range ipList {
			if isInternalAddress(ip.String()) {
				ctx.Error("SSRF protection: Invalid host", fasthttp.StatusBadRequest)
				return
			}
		}
	}

	// Use fasthttp.Client to fetch with timeout
	client := &fasthttp.Client{
		ReadTimeout:         30 * time.Second,
		WriteTimeout:        30 * time.Second,
		MaxIdleConnDuration: 5 * time.Second,
		MaxConnsPerHost:     5,
		MaxResponseBodySize: 1024 * 1024, // Limit to 1MB
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	maxRedirectCounts := 5
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	// Limit response size check after receiving
	if len(bodyBytes) > 1024*1024 { // 1MB
		ctx.Error("Response too large", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// isInternalAddress checks if the host is an internal address to prevent SSRF
func isInternalAddress(host string) bool {
	// Remove port if present
	if colonIndex := strings.LastIndex(host, ":"); colonIndex != -1 {
		host = host[:colonIndex]
	}

	// Check for IP addresses
	ip := net.ParseIP(host)
	if ip != nil {
		// Check for private IP ranges
		return ip.IsPrivate() || ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsUnspecified()
	}

	// Check for local hostnames
	switch strings.ToLower(host) {
	case "localhost":
		return true
	case "0.0.0.0":
		return true
	case "::1":
		return true
	case "::":
		return true
	default:
		// Check for common internal hostnames
		lowerHost := strings.ToLower(host)
		if strings.Contains(lowerHost, ".local") || 
		   strings.Contains(lowerHost, "internal.") ||
		   strings.Contains(lowerHost, ".internal") ||
		   strings.HasSuffix(lowerHost, ".svc.cluster.local") {
			return true
		}
		return false
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)

	for {
		tokenType := tokenizer.Next()
		if tokenType == html.ErrorToken {
			return title, description, nil // End of document reached
		}

		token := tokenizer.Token()
		if tokenType == html.StartTagToken || tokenType == html.EndTagToken {
			tagName := token.Data

			// Look for title tag
			if tagName == "title" && tokenType == html.StartTagToken {
				tokenType = tokenizer.Next()
				if tokenType == html.TextToken {
					title = token.String()
				}
			}

			// Look for meta tags
			if tagName == "meta" && tokenType == html.StartTagToken {
				var name, property, content string
				for _, attr := range token.Attr {
					switch attr.Key {
					case "name":
						name = strings.ToLower(attr.Val)
					case "property":
						property = strings.ToLower(attr.Val)
					case "content":
						content = attr.Val
					}
				}

				// Check for description in either name or property attributes
				if (name == "description" || property == "og:description") && content != "" {
					description = content
				}
			}
		}
	}
}

