// isPrivateIP checks if an IP address belongs to a private network
func isPrivateIP(ip net.IP) bool {
	privateNetworks := []*net.IPNet{
		mustParseCIDR("10.0.0.0/8"),
		mustParseCIDR("172.16.0.0/12"),
		mustParseCIDR("192.168.0.0/16"),
		mustParseCIDR("127.0.0.0/8"),
		mustParseCIDR("::1/128"),      // IPv6 localhost
		mustParseCIDR("fc00::/7"),     // IPv6 private
		mustParseCIDR("fe80::/10"),    // IPv6 link-local
	}

	for _, network := range privateNetworks {
		if network.Contains(ip) {
			return true
		}
	}
	return false
}

// Helper function to parse CIDR (this will panic if the CIDR is invalid, which should not happen with our hardcoded values)
func mustParseCIDR(cidr string) *net.IPNet {
	_, ipNet, err := net.ParseCIDR(cidr)
	if err != nil {
		panic(err)
	}
	return ipNet
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	z := html.NewTokenizer(r)

	for {
		tt := z.Next()
		switch tt {
		case html.ErrorToken:
			return title, description, nil // End of document
		case html.StartTagToken, html.EndTagToken:
			tn, _ := z.TagName()
			if bytes.Equal(tn, []byte("title")) {
				if tt == html.StartTagToken {
					// Get the text content of the title tag
					tt = z.Next()
					if tt == html.TextToken {
						title = string(z.Text())
					}
				}
			} else if bytes.Equal(tn, []byte("meta")) {
				if tt == html.StartTagToken {
					key, val := getMetaAttr(z)
					if key == "name" && val == "description" {
						description = getMetaContent(z)
					} else if key == "property" && val == "og:description" {
						description = getMetaContent(z)
					}
				}
			}
		}
	}
}

// getMetaAttr gets the name and content attributes from a meta tag
func getMetaAttr(z *html.Tokenizer) (string, string) {
	for {
		key, val, more := z.TagAttr()
		if !more {
			break
		}
		if string(key) == "name" || string(key) == "property" {
			return string(key), string(val)
		}
	}
	return "", ""
}

// getMetaContent gets the content attribute value from a meta tag
func getMetaContent(z *html.Tokenizer) string {
	for {
		key, val, more := z.TagAttr()
		if !more {
			break
		}
		if string(key) == "content" {
			return string(val)
		}
	}
	return ""
}

