	// Use fasthttp.Client to fetch with timeout
	client := &fasthttp.Client{
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     2,
		MaxResponseBodySize: 5 * 1024 * 1024, // Limit response size to 5MB
		Dial: (&fasthttp.TCPDialer{
			Concurrency:      4,
			DNSCacheDuration: time.Hour,
		}).Dial,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	maxRedirectCounts := 5 // Limit redirects
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// isInternalAddress checks if a hostname resolves to a private/internal IP address
func isInternalAddress(host string) bool {
	// Check for localhost variations
	if host == "localhost" || strings.ToLower(host) == "localhost" {
		return true
	}

	// Check for loopback addresses
	if strings.HasPrefix(host, "127.") || host == "::1" {
		return true
	}

	// Check for private network ranges by attempting resolution
	ips, err := net.LookupIP(host)
	if err != nil {
		// If we can't resolve it, assume it's not internal
		return false
	}

	for _, ip := range ips {
		if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
			return true
		}
	}

	return false
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	title = findTagContent(doc, "title")
	description = findMetaDescription(doc)

	return title, description, nil
}

// findTagContent finds the content of the first occurrence of a tag
func findTagContent(n *html.Node, tagName string) string {
	if n.Type == html.ElementNode && n.Data == tagName {
		return extractText(n.FirstChild)
	}

	for c := n.FirstChild; c != nil; c = c.NextSibling {
		result := findTagContent(c, tagName)
		if result != "" {
			return result
		}
	}

	return ""
}

// findMetaDescription finds the content of the meta description tag
func findMetaDescription(n *html.Node) string {
	if n.Type == html.ElementNode && n.Data == "meta" {
		nameAttr := getAttributeValue(n, "name")
		propertyAttr := getAttributeValue(n, "property") // For og:description
		contentAttr := getAttributeValue(n, "content")

		if (strings.ToLower(nameAttr) == "description" || 
			 strings.ToLower(propertyAttr) == "og:description") && 
			 contentAttr != "" {
			return contentAttr
		}
	}

	for c := n.FirstChild; c != nil; c = c.NextSibling {
		result := findMetaDescription(c)
		if result != "" {
			return result
		}
	}

	return ""
}

// extractText extracts text content from a node
func extractText(n *html.Node) string {
	if n == nil {
		return ""
	}

	if n.Type == html.TextNode {
		return strings.TrimSpace(n.Data)
	}

	var text string
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		text += extractText(c)
	}

	return strings.TrimSpace(text)
}

// getAttributeValue gets the value of an attribute by name
func getAttributeValue(n *html.Node, attrName string) string {
	for _, a := range n.Attr {
		if a.Key == attrName {
			return a.Val
		}
	}
	return ""
}

