// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	z := html.NewTokenizer(r)
	var foundTitle, foundDescription bool

	for {
		tt := z.Next()
		switch tt {
		case html.ErrorToken:
			return // End of document
		case html.StartTagToken, html.EndTagToken:
			tn, _ := z.TagName()
			if !foundTitle && bytes.Equal(tn, []byte("title")) {
				if tt == html.StartTagToken {
					// Get next token which should contain the text
					nextTT := z.Next()
					if nextTT == html.TextToken {
						title = string(z.Text())
						foundTitle = true
					}
				}
			} else if bytes.Equal(tn, []byte("meta")) {
				if tt == html.StartTagToken {
					var key, val []byte
					var nameAttr, contentAttr string
					var isDescriptionMeta, isOGDescription bool

					for {
						key, val, more := z.TagAttr()
						if bytes.Equal(key, []byte("name")) {
							nameAttr = string(val)
						} else if bytes.Equal(key, []byte("property")) {
							// Check for Open Graph properties
							propVal := string(val)
							if propVal == "og:description" {
								isOGDescription = true
							}
						}
						if bytes.Equal(key, []byte("content")) {
							contentAttr = string(val)
						}
						if !more {
							break
						}
					}

					// Check if this is the description meta tag
					if nameAttr == "description" {
						isDescriptionMeta = true
					}

					if isDescriptionMeta || isOGDescription {
						description = contentAttr
						foundDescription = true
					}
				}
			}

			// Early exit if both title and description are found
			if foundTitle && foundDescription {
				return
			}
		}
	}
}

